#include <bits/stdc++.h>
using namespace std;

// Check if adding numbers in a set produces any carry in base 10
bool no_carry(const vector<int>& nums, int mask) {
    int carry[10] = {0}; // max 7 digits since w_i <= 1e6
    for (int i = 0; i < (int)nums.size(); i++) {
        if (mask & (1 << i)) {
            int x = nums[i];
            int pos = 0;
            while (x > 0) {
                int d = x % 10;
                carry[pos] += d;
                x /= 10;
                pos++;
            }
        }
    }
    for (int i = 0; i < 10; i++) {
        if (carry[i] >= 10) return false;
    }
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;
    vector<int> w(N);
    for (int i = 0; i < N; i++) {
        cin >> w[i];
    }

    int best = 0;
    int total_masks = 1 << N;
    for (int mask = 1; mask < total_masks; mask++) {
        int cnt = __builtin_popcount(mask);
        if (cnt <= best) continue;
        if (no_carry(w, mask)) {
            best = cnt;
        }
    }
    cout << best << "\n";
    return 0;
}
